import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

/**
 * Tests for mutable collection property naming rule
 * Issue: Mutable collection property name should not be SCREAMING_SNAKE_CASE
 * https://developer.android.com/kotlin/style-guide#non-constant_names
 */
class PropertyNamingRuleMutableCollectionTest {
    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Test
    fun `Given a mutable collection in object with lower camel case name then do not emit`() {
        val code =
            """
            object SomeObject {
                val someMap: MutableMap<String, String> = mutableMapOf()
                val someList: MutableList<String> = mutableListOf()
                val someSet: MutableSet<String> = mutableSetOf()
                val someCollection: MutableCollection<String> = mutableListOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a mutable collection in object with screaming snake case name then do emit`() {
        val code =
            """
            object SomeObject {
                val SOME_MAP: MutableMap<String, String> = mutableMapOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(2, 9, "Property name should start with a lowercase letter and use camel case")
    }

    @Test
    fun `Given a mutable collection in anonymous object with lower camel case name then do not emit`() {
        val code =
            """
            val obj = object : SomeInterface {
                val someMap: MutableMap<String, String> = mutableMapOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a mutable collection in companion object with lower camel case name then do not emit`() {
        val code =
            """
            class Foo {
                companion object {
                    val someMap: MutableMap<String, String> = mutableMapOf()
                    val someList: MutableList<Int> = mutableListOf()
                }
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an immutable collection in object with screaming snake case name then do not emit`() {
        val code =
            """
            object SomeObject {
                val SOME_MAP: Map<String, String> = mapOf()
                val SOME_LIST: List<String> = listOf()
                val SOME_SET: Set<String> = setOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an immutable collection in object with lower camel case name then do emit`() {
        val code =
            """
            object SomeObject {
                val someMap: Map<String, String> = mapOf()
            }
            """.trimIndent()
        @Suppress("ktlint:standard:argument-list-wrapping", "ktlint:standard:max-line-length")
        propertyNamingRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(2, 9, "Property name should use the screaming snake case notation when the value can not be changed")
    }

    @Test
    fun `Given a mutable collection with qualified name then do not emit`() {
        val code =
            """
            object SomeObject {
                val someMap: kotlin.collections.MutableMap<String, String> = mutableMapOf()
                val someList: java.util.MutableList<String> = mutableListOf()
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a complex type with mutable collection as generic parameter then do not emit`() {
        val code =
            """
            object SomeObject {
                val someMap: Map<String, MutableList<String>> = mapOf()
                val someOther: Pair<String, MutableMap<Int, String>> = Pair("", mutableMapOf())
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a top level mutable collection with lower camel case name then do not emit`() {
        val code =
            """
            val someMap: MutableMap<String, String> = mutableMapOf()
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a const mutable property in object (which should not be possible but test anyway)`() {
        // Note: This would be a compile error in real Kotlin, but testing the rule's behavior
        val code =
            """
            object SomeObject {
                const val SOME_VALUE: String = "value"
            }
            """.trimIndent()
        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }
}
"}

